/* The search input historically exposed only a `placeholder`, which is NOT
   an accessible name: it is not reliably announced to assistive tech and it
   vanishes the moment the user types, leaving the field unlabeled. These
   tests pin the fix — a stable accessible name via `aria-label` — and guard
   against regressions that would strip it or break the existing
   `input[type="text"]` selector. */
describe('search input accessible name', () => {
  it('exposes a non-empty accessible name via aria-label', () => {
    const { searchInput } = setup();
    const ariaLabel = searchInput.getAttribute('aria-label');
    expect(typeof ariaLabel).toBe('string');
    expect((ariaLabel ?? '').trim().length).toBeGreaterThan(0);
  });

  it('uses "Search files" as the aria-label value', () => {
    const { searchInput } = setup();
    expect(searchInput.getAttribute('aria-label')).toBe('Search files');
  });

  it('keeps the accessible name after the user types (unlike the placeholder)', () => {
    // The whole reason an aria-label is needed: a placeholder disappears as
    // soon as the field has a value, so it cannot serve as a label. The
    // accessible name must remain stable regardless of the input's value.
    const { searchInput } = setup();
    searchInput.value = 'report.pdf';
    expect(searchInput.getAttribute('aria-label')).toBe('Search files');
  });

  it('preserves the "Search..." placeholder as a hint alongside the accessible name', () => {
    const { searchInput } = setup();
    // The fix adds an accessible name; it must not remove the placeholder hint.
    expect(searchInput.getAttribute('placeholder')).toBe('Search...');
  });

  it('remains a single input[type="text"] so existing selectors/CSS keep matching', () => {
    // render-search.test.ts / toolbar-handlers.test.ts resolve the field via
    // `input[type="text"]`; the accessibility fix must not change the input's
    // type or introduce an extra text input that would shift that selector.
    const { root, searchInput } = setup();
    const textInputs = root.querySelectorAll('input[type="text"]');
    expect(textInputs).toHaveLength(1);
    expect(textInputs[0]).toBe(searchInput);
    expect(searchInput.type).toBe('text');
  });

  it('keeps the accessible name when the widget is moved into the dialog on open', () => {
    // The shared widget is MOVED (same node refs) into the dialog body when
    // it opens; the accessible name must travel with it (no clone/loss).
    const { searchInput, trigger } = setup();
    expect(searchInput.getAttribute('aria-label')).toBe('Search files');

    trigger.click();

    expect(searchInput.getAttribute('aria-label')).toBe('Search files');
  });
});

