+/* ===========================================================================
+ * Loading indicator while results are being fetched
+ *
+ * `render()` awaits the route's fetch (browse/search) before it can render a
+ * table. During that in-flight window the results panel must not be blank — a
+ * synchronous placeholder ("Loading…") is committed before the first `await`
+ * so the user sees that work is in progress instead of an empty/broken UI.
+ *
+ * The placeholder is set with `textContent` before the `await`, so it is in the
+ * DOM immediately (before any microtask resolves the fetch). It is naturally
+ * replaced on success — `renderBrowse`/`renderSearch` wipe `.results` and
+ * append the table — and on error — the `catch` sets `.results.textContent` to
+ * the error message — so no explicit cleanup is needed. These tests pin that
+ * contract for both the browse and search dispatch paths.
+ * ========================================================================= */
+describe('loading indicator while results are being fetched', () => {
+  /**
+   * Install a fetch stub whose BROWSE response for `heldPath` stays pending
+   * until `release()` is invoked, mimicking a slow network so a test can
+   * observe the in-flight UI. All other browse paths resolve immediately.
+   */
+  function holdBrowseFetch(heldPath: string): { release: () => void } {
+    let release!: () => void;
+    const held = new Promise<Response>((resolve) => {
+      release = () =>
+        resolve(
+          mockResponse({
+            body: browseResult({
+              path: heldPath,
+              entries: [
+                fileEntry({
+                  name: 'child-of-' + heldPath,
+                  path: joinPathHelper(heldPath, 'child-of-' + heldPath),
+                }),
+              ],
+              fileCount: 1,
+              totalSize: 1,
+            }),
+          }),
+        );
+    });
+    fetchMock.mockImplementation(async (url, init) => {
+      const u = String(url);
+      const method = (init?.method ?? 'GET').toUpperCase();
+      if (method === 'GET' && u.includes('/browse')) {
+        const path = decodeURIComponent(u.split('path=')[1] ?? '');
+        if (path === heldPath) return held;
+        return mockResponse({ body: browseResult({ path }) });
+      }
+      return mockResponse({ status: 200, body: {} });
+    });

  });

  it('renders a search text input with the Search... placeholder and a Search button', () => {
    const { searchInput, searchBtn } = setup();
